using Microsoft.Extensions.DependencyInjection;

// Fixed: accepts IServiceScopeFactory instead of scoped IUserService directly,
// so this singleton no longer captures a scoped dependency.
public class CacheService : ICacheService
{
    private readonly IServiceScopeFactory _scopeFactory;

    public CacheService(IServiceScopeFactory scopeFactory)
    {
        _scopeFactory = scopeFactory;
    }

    private IUserService GetUserService()
    {
        using var scope = _scopeFactory.CreateScope();
        return scope.ServiceProvider.GetRequiredService<IUserService>();
    }
}

