using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();

// BREAKING CHANGE 1 – ValidateOnBuild is now true by default in Development (.NET 9).
// A singleton that captures a scoped service via the root provider throws at startup.
// Fix: inject IServiceScopeFactory into the singleton and create scopes on demand.
builder.Services.AddSingleton<ICacheService, CacheService>();

// BREAKING CHANGE 2 – Default primary handler is SocketsHttpHandler, not HttpClientHandler.
// The old cast to HttpClientHandler throws InvalidCastException at runtime.
// ConfigureHttpMessageHandlerBuilder is also obsolete.
// Fix: use ConfigurePrimaryHttpMessageHandler with a SocketsHttpHandler factory.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler
    {
        UseCookies = false
    });

builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

